css:
.rt-kpi-cust-snap {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  container-type: inline-size;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}
.rt-kpi-cust-snap .kpiband {
  display: grid;
  grid-template-columns: repeat(6, 1fr);
  gap: 14px;
}
.rt-kpi-cust-snap .kpi {
  position: relative;
  min-width: 0;
  display: flex;
  flex-direction: column;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: border-color .15s ease, transform .15s ease, box-shadow .15s ease, background-color .15s ease;
}
.rt-kpi-cust-snap .kpi:not(.hero):hover {
  background: var(--surface-raised);
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
  transform: translateY(-2px);
  box-shadow: 0 1px 0 rgba(255,255,255,.04) inset, 0 10px 26px rgba(0,0,0,.55), 0 0 22px -10px color-mix(in srgb, var(--accent) 55%, transparent);
}
.rt-kpi-cust-snap .kpi:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
.rt-kpi-cust-snap .kpi .label {
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--muted);
  display: flex;
  align-items: center;
}
.rt-kpi-cust-snap .kpi .label::before {
  content: "";
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  margin-right: 7px;
  background: var(--accent);
  flex: 0 0 auto;
}
.rt-kpi-cust-snap .kpi .value {
  font: 800 26px/1.1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  font-variant-numeric: tabular-nums;
  color: var(--ink);
  margin-top: 8px;
  overflow-wrap: anywhere;
}
.rt-kpi-cust-snap .kpi .ctx {
  font: 600 11px/1.3 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  font-variant-numeric: tabular-nums;
  color: var(--muted);
  margin-top: 5px;
  overflow-wrap: anywhere;
}
.rt-kpi-cust-snap .kpi.hero {
  background: linear-gradient(135deg, var(--accent), var(--accent-2));
  border-color: transparent;
  box-shadow: 0 1px 0 rgba(255,255,255,.18) inset, 0 6px 18px rgba(0,0,0,.5), 0 0 28px -8px color-mix(in srgb, var(--accent) 60%, transparent);
}
.rt-kpi-cust-snap .kpi.hero:hover {
  transform: translateY(-2px);
  box-shadow: 0 1px 0 rgba(255,255,255,.2) inset, 0 10px 28px rgba(0,0,0,.55), 0 0 34px -6px color-mix(in srgb, var(--accent-2) 55%, transparent);
}
.rt-kpi-cust-snap .kpi.hero .label,
.rt-kpi-cust-snap .kpi.hero .value,
.rt-kpi-cust-snap .kpi.hero .ctx { color: #0B0B0D; }
.rt-kpi-cust-snap .kpi.hero .label { opacity: .82; }
.rt-kpi-cust-snap .kpi.hero .ctx { opacity: .78; }
.rt-kpi-cust-snap .kpi.hero .label::before { background: #0B0B0D; }
@container (max-width: 1100px) {
  .rt-kpi-cust-snap .kpiband { grid-template-columns: repeat(3, 1fr); }
}
@container (max-width: 640px) {
  .rt-kpi-cust-snap .kpiband { grid-template-columns: repeat(2, 1fr); }
}
@container (max-width: 360px) {
  .rt-kpi-cust-snap .kpiband { grid-template-columns: 1fr; }
  .rt-kpi-cust-snap .kpi { padding: 14px; }
}
@media (prefers-reduced-motion: reduce) {
  .rt-kpi-cust-snap .kpi,
  .rt-kpi-cust-snap .kpi:not(.hero):hover,
  .rt-kpi-cust-snap .kpi.hero:hover {
    transition: none;
    transform: none;
  }
}
